std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a buffer_adaptor object from the source buffer
    hexi::buffer_adaptor<const std::vector<uint8_t>&> adaptor(const_cast<std::vector<uint8_t>&>(source_buffer));

    // Check if the requested bytes are available in the buffer
    if (bytes_to_read > adaptor.available()) {
        HEXI_THROW(hexi::buffer_underrun(bytes_to_read, 0, adaptor.available()));
    }

    // Use the read function to copy data from the buffer to the destination
    std::vector<uint8_t> destination(bytes_to_read);
    adaptor.read(destination.data(), bytes_to_read);

    // Return the destination buffer
    return destination;
}

