#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // Write the size of the vector as a prefix using native endian
    writer << hexi::pmc::endian::as_native_t(container.size());

    // Write the container elements using the put method with iterators
    writer.put(container.begin(), container.end());
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    std::vector<uint32_t> result;

    // Read the count using the operator>> with endian conversion
    uint32_t count;
    reader >> hexi::pmc::endian::as_native_t(count);

    // Check if read was successful
    if (reader.state() != hexi::pmc::stream_state::ok) {
        return result; // Return empty vector on error
    }

    // Resize the result vector based on the count
    result.resize(count);

    // Read the container elements using the get method with iterators
    if (!result.empty()) {
        reader.get(result.begin(), result.end());
    }

    return result;
}
