void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, hexi::buffer_seek direction, std::size_t offset) {
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Write placeholder header
    uint32_t placeholder = 0;
    buffer.write(&placeholder, sizeof(placeholder));

    // Write body data
    uint32_t body = 999;
    buffer.write(&body, sizeof(body));

    // Seek back to header position
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Update header
    buffer.write(&header_value, sizeof(header_value));

    // Seek to end of data
    buffer.write_seek(hexi::buffer_seek::sk_absolute, sizeof(header_value) + sizeof(body));
}

