    // Create a buffer_adaptor for the mutable buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(mutable_buffer);

    // Create a binary_stream object using the buffer adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Deserialize packet_id as raw integer using operator>>
    stream >> packet.packet_id;

    // Deserialize tags vector using prefixed_varint adaptor
    stream >> hexi::prefixed_varint(packet.tags);

    // Deserialize data string using prefixed_varint adaptor
    stream >> hexi::prefixed_varint(packet.data);

    return packet;
}

